class Solution:
    def climbStairs(self, n: int) -> int:
        if n <= 2:
            return n
        return self.climbStairs(n - 1) + self.climbStairs(n - 2)

class Solution:
    def climbStairs(self, n: int) -> int:
        from functools import lru_cache

        @lru_cache(None)  # memoize all calls
        def dp(i):
            if i <= 2:
                return i
            return dp(i - 1) + dp(i - 2)

        return dp(n)

class Solution:
    def climbStairs(self, n: int) -> int:
        if n <= 2:
            return n
        dp = [0] * (n + 1)
        dp[1], dp[2] = 1, 2
        for i in range(3, n + 1):
            dp[i] = dp[i - 1] + dp[i - 2]
        return dp[n]

class Solution:
    def climbStairs(self, n: int) -> int:
        if n <= 2:
            return n
        prev, curr = 1, 2
        for _ in range(3, n + 1):
            prev, curr = curr, prev + curr
        return curr

class Solution:
    def climbStairs(self, n: int) -> int:
        # The nth Fibonacci number (shifted by 1 for this problem)
        # F(n) = (phi^n - psi^n) / sqrt(5)
        # where phi = (1 + sqrt(5)) / 2, psi = (1 - sqrt(5)) / 2
        sqrt5 = 5 ** 0.5
        phi = (1 + sqrt5) / 2
        psi = (1 - sqrt5) / 2
        return int((phi ** (n + 1) - psi ** (n + 1)) / sqrt5)

class Solution:
    def minCostClimbingStairs(self, cost: list[int]) -> int:
        from functools import cache

        @cache
        def dp(i):
            # base case: can start from step 0 or 1 for free
            if i <= 1:
                return 0
            # to reach step i, come from i-1 or i-2 and pay their cost
            return min(dp(i - 1) + cost[i - 1], dp(i - 2) + cost[i - 2])

        return dp(len(cost))  # reach the top (one past the last step)

class Solution:
    def minCostClimbingStairs(self, cost: list[int]) -> int:
        n = len(cost)
        dp = [0] * (n + 1)  # dp[n] is the top (one past the end)
        for i in range(2, n + 1):
            # come from i-1 or i-2
            dp[i] = min(dp[i - 1] + cost[i - 1], dp[i - 2] + cost[i - 2])
        return dp[n]

class Solution:
    def minCostClimbingStairs(self, cost: list[int]) -> int:
        prev, curr = 0, 0
        for i in range(2, len(cost) + 1):
            prev, curr = curr, min(curr + cost[i - 1], prev + cost[i - 2])
        return curr

class Solution:
    def rob(self, nums: list[int]) -> int:
        def helper(i):
            if i < 0:
                return 0
            # rob house i, or skip it
            return max(helper(i - 2) + nums[i], helper(i - 1))

        return helper(len(nums) - 1)

class Solution:
    def rob(self, nums: list[int]) -> int:
        from functools import cache

        @cache
        def dp(i):
            if i < 0:
                return 0
            return max(dp(i - 2) + nums[i], dp(i - 1))

        return dp(len(nums) - 1)

class Solution:
    def rob(self, nums: list[int]) -> int:
        if not nums:
            return 0
        if len(nums) == 1:
            return nums[0]
        dp = [0] * len(nums)
        dp[0] = nums[0]
        dp[1] = max(nums[0], nums[1])
        for i in range(2, len(nums)):
            dp[i] = max(dp[i - 2] + nums[i], dp[i - 1])
        return dp[-1]

class Solution:
    def rob(self, nums: list[int]) -> int:
        prev, curr = 0, 0
        for n in nums:
            prev, curr = curr, max(prev + n, curr)
        return curr

class Solution:
    def rob(self, nums: list[int]) -> int:
        if len(nums) == 1:
            return nums[0]

        from functools import cache

        def rob_linear(arr):
            @cache
            def dp(i):
                if i < 0:
                    return 0
                return max(dp(i - 2) + arr[i], dp(i - 1))
            return dp(len(arr) - 1)

        # case 1: skip last house, case 2: skip first house
        return max(rob_linear(nums[:-1]), rob_linear(nums[1:]))

class Solution:
    def rob(self, nums: list[int]) -> int:
        if len(nums) == 1:
            return nums[0]

        def rob_linear(arr):
            prev, curr = 0, 0
            for n in arr:
                prev, curr = curr, max(prev + n, curr)
            return curr

        # case 1: rob houses 0..n-2 (skip last)
        # case 2: rob houses 1..n-1 (skip first)
        return max(rob_linear(nums[:-1]), rob_linear(nums[1:]))

class Solution:
    def longestPalindrome(self, s: str) -> str:
        def expand(left, right):
            while left >= 0 and right < len(s) and s[left] == s[right]:
                left -= 1
                right += 1
            # return the valid palindrome substring
            return s[left + 1:right]

        longest = ""
        for i in range(len(s)):
            # odd-length palindrome (center = i)
            pal1 = expand(i, i)
            # even-length palindrome (center between i and i+1)
            pal2 = expand(i, i + 1)
            longest = max(longest, pal1, pal2, key=len)
        return longest

class Solution:
    def longestPalindrome(self, s: str) -> str:
        n = len(s)
        if n == 0:
            return ""
        # dp[i][j] = True if s[i:j+1] is a palindrome
        dp = [[False] * n for _ in range(n)]
        start, max_len = 0, 1

        # every single character is a palindrome
        for i in range(n):
            dp[i][i] = True

        # check for length 2
        for i in range(n - 1):
            if s[i] == s[i + 1]:
                dp[i][i + 1] = True
                start, max_len = i, 2

        # check for lengths 3 to n
        for length in range(3, n + 1):
            for i in range(n - length + 1):
                j = i + length - 1
                # s[i:j+1] is palindrome if s[i] == s[j] and s[i+1:j] is palindrome
                if s[i] == s[j] and dp[i + 1][j - 1]:
                    dp[i][j] = True
                    start, max_len = i, length

        return s[start:start + max_len]

class Solution:
    def countSubstrings(self, s: str) -> int:
        count = 0

        def expand(left, right):
            nonlocal count
            while left >= 0 and right < len(s) and s[left] == s[right]:
                count += 1  # found a palindrome
                left -= 1
                right += 1

        for i in range(len(s)):
            expand(i, i)       # odd-length
            expand(i, i + 1)   # even-length
        return count

class Solution:
    def countSubstrings(self, s: str) -> int:
        n = len(s)
        dp = [[False] * n for _ in range(n)]
        count = 0

        # single characters
        for i in range(n):
            dp[i][i] = True
            count += 1

        # length 2
        for i in range(n - 1):
            if s[i] == s[i + 1]:
                dp[i][i + 1] = True
                count += 1

        # length 3 to n
        for length in range(3, n + 1):
            for i in range(n - length + 1):
                j = i + length - 1
                if s[i] == s[j] and dp[i + 1][j - 1]:
                    dp[i][j] = True
                    count += 1

        return count

class Solution:
    def numDecodings(self, s: str) -> int:
        from functools import cache

        @cache
        def dp(i):
            # base case: reached the end
            if i == len(s):
                return 1
            # leading zero is invalid
            if s[i] == '0':
                return 0

            ways = dp(i + 1)  # decode 1 digit
            # try decoding 2 digits
            if i + 1 < len(s) and int(s[i:i+2]) <= 26:
                ways += dp(i + 2)
            return ways

        return dp(0)

class Solution:
    def numDecodings(self, s: str) -> int:
        if not s or s[0] == '0':
            return 0
        n = len(s)
        dp = [0] * (n + 1)
        dp[0] = 1  # empty string has 1 way
        dp[1] = 1  # first char is valid (we checked s[0] != '0')

        for i in range(2, n + 1):
            # 1-digit decode
            if s[i - 1] != '0':
                dp[i] += dp[i - 1]
            # 2-digit decode
            two_digit = int(s[i - 2:i])
            if 10 <= two_digit <= 26:
                dp[i] += dp[i - 2]
        return dp[n]

class Solution:
    def numDecodings(self, s: str) -> int:
        if not s or s[0] == '0':
            return 0
        prev2, prev1 = 1, 1  # dp[i-2], dp[i-1]
        for i in range(2, len(s) + 1):
            curr = 0
            if s[i - 1] != '0':
                curr += prev1
            two_digit = int(s[i - 2:i])
            if 10 <= two_digit <= 26:
                curr += prev2
            prev2, prev1 = prev1, curr
        return prev1

class Solution:
    def coinChange(self, coins: list[int], amount: int) -> int:
        from functools import cache

        @cache
        def dp(amt):
            if amt == 0:
                return 0
            if amt < 0:
                return float('inf')  # impossible
            # try every coin, pick the one that gives min total
            min_coins = float('inf')
            for coin in coins:
                min_coins = min(min_coins, dp(amt - coin) + 1)
            return min_coins

        result = dp(amount)
        return result if result != float('inf') else -1

class Solution:
    def coinChange(self, coins: list[int], amount: int) -> int:
        dp = [float('inf')] * (amount + 1)
        dp[0] = 0  # 0 coins to make amount 0

        for i in range(1, amount + 1):
            for coin in coins:
                if i - coin >= 0:
                    dp[i] = min(dp[i], dp[i - coin] + 1)

        return dp[amount] if dp[amount] != float('inf') else -1

class Solution:
    def coinChange(self, coins: list[int], amount: int) -> int:
        from collections import deque

        if amount == 0:
            return 0

        queue = deque([amount])  # start from target amount
        visited = {amount}
        steps = 0

        while queue:
            steps += 1
            for _ in range(len(queue)):
                curr = queue.popleft()
                for coin in coins:
                    next_amt = curr - coin
                    if next_amt == 0:
                        return steps
                    if next_amt > 0 and next_amt not in visited:
                        visited.add(next_amt)
                        queue.append(next_amt)

        return -1

class Solution:
    def maxProduct(self, nums: list[int]) -> int:
        max_prod = float('-inf')
        for i in range(len(nums)):
            prod = 1
            for j in range(i, len(nums)):
                prod *= nums[j]
                max_prod = max(max_prod, prod)
        return max_prod

class Solution:
    def maxProduct(self, nums: list[int]) -> int:
        if not nums:
            return 0
        max_prod = min_prod = result = nums[0]

        for i in range(1, len(nums)):
            n = nums[i]
            # compute candidates
            candidates = (n, max_prod * n, min_prod * n)
            max_prod = max(candidates)
            min_prod = min(candidates)
            result = max(result, max_prod)
        return result

class Solution:
    def wordBreak(self, s: str, wordDict: list[str]) -> bool:
        from functools import cache
        word_set = set(wordDict)

        @cache
        def dp(i):
            if i == len(s):
                return True  # segmented the entire string
            # try each word as the next segment
            for word in word_set:
                if s[i:i+len(word)] == word and dp(i + len(word)):
                    return True
            return False

        return dp(0)

class Solution:
    def wordBreak(self, s: str, wordDict: list[str]) -> bool:
        word_set = set(wordDict)
        n = len(s)
        dp = [False] * (n + 1)
        dp[0] = True  # empty string

        for i in range(1, n + 1):
            for j in range(i):
                if dp[j] and s[j:i] in word_set:
                    dp[i] = True
                    break  # found a valid segmentation
        return dp[n]

class Solution:
    def wordBreak(self, s: str, wordDict: list[str]) -> bool:
        from collections import deque
        word_set = set(wordDict)
        queue = deque([0])  # start at index 0
        visited = {0}

        while queue:
            start = queue.popleft()
            if start == len(s):
                return True
            # try each word starting at 'start'
            for end in range(start + 1, len(s) + 1):
                if end in visited:
                    continue
                if s[start:end] in word_set:
                    queue.append(end)
                    visited.add(end)

        return False

class Solution:
    def wordBreak(self, s: str, wordDict: list[str]) -> bool:
        # Build a trie from the dictionary words
        class TrieNode:
            def __init__(self):
                self.children = {}
                self.is_word = False

        root = TrieNode()
        for word in wordDict:
            node = root
            for ch in word:
                if ch not in node.children:
                    node.children[ch] = TrieNode()
                node = node.children[ch]
            node.is_word = True  # mark end of a dictionary word

        n = len(s)
        dp = [False] * (n + 1)
        dp[0] = True  # empty prefix is always reachable

        for i in range(n):          # i = start of the next segment
            if not dp[i]:           # s[:i] can't be segmented -> skip
                continue
            node = root
            for j in range(i, n):   # walk the trie forward from i
                ch = s[j]
                if ch not in node.children:
                    break           # no dictionary word continues this way
                node = node.children[ch]
                if node.is_word:    # s[i:j+1] is a word and s[:i] is segmentable
                    dp[j + 1] = True
        return dp[n]

class Solution:
    def lengthOfLIS(self, nums: list[int]) -> int:
        def is_increasing(seq):
            for i in range(1, len(seq)):
                if seq[i] <= seq[i-1]:
                    return False
            return True

        max_len = 0
        n = len(nums)
        # generate all 2^n subsequences
        for mask in range(1 << n):
            subseq = [nums[i] for i in range(n) if mask & (1 << i)]
            if is_increasing(subseq):
                max_len = max(max_len, len(subseq))
        return max_len

class Solution:
    def lengthOfLIS(self, nums: list[int]) -> int:
        if not nums:
            return 0
        dp = [1] * len(nums)  # each element is an LIS of length 1

        for i in range(1, len(nums)):
            for j in range(i):
                if nums[j] < nums[i]:
                    dp[i] = max(dp[i], dp[j] + 1)
        return max(dp)

class Solution:
    def lengthOfLIS(self, nums: list[int]) -> int:
        from bisect import bisect_left
        tails = []  # tails[i] = smallest tail of any LIS of length i+1

        for num in nums:
            pos = bisect_left(tails, num)
            if pos == len(tails):
                tails.append(num)  # extend the longest LIS
            else:
                tails[pos] = num   # replace to keep tails[pos] minimal
        return len(tails)

class Solution:
    def canPartition(self, nums: list[int]) -> bool:
        total = sum(nums)
        if total % 2 != 0:
            return False
        target = total // 2

        n = len(nums)
        # try all 2^n subsets
        for mask in range(1 << n):
            subset_sum = sum(nums[i] for i in range(n) if mask & (1 << i))
            if subset_sum == target:
                return True
        return False

class Solution:
    def canPartition(self, nums: list[int]) -> bool:
        total = sum(nums)
        if total % 2 != 0:
            return False
        target = total // 2

        from functools import cache

        @cache
        def dp(i, remaining):
            if remaining == 0:
                return True  # found a subset that sums to target
            if i >= len(nums) or remaining < 0:
                return False
            # try including nums[i] or skipping it
            return dp(i + 1, remaining - nums[i]) or dp(i + 1, remaining)

        return dp(0, target)

class Solution:
    def canPartition(self, nums: list[int]) -> bool:
        total = sum(nums)
        if total % 2 != 0:
            return False
        target = total // 2

        dp = {0}  # set of reachable sums
        for num in nums:
            # create new sums by adding num to each existing sum
            new_sums = set()
            for s in dp:
                new_sums.add(s + num)
            dp.update(new_sums)
            if target in dp:
                return True  # early exit
        return target in dp

class Solution:
    def canPartition(self, nums: list[int]) -> bool:
        total = sum(nums)
        if total % 2 != 0:
            return False
        target = total // 2

        dp = [False] * (target + 1)
        dp[0] = True

        for num in nums:
            # iterate backwards to avoid using num multiple times
            for s in range(target, num - 1, -1):
                dp[s] = dp[s] or dp[s - num]
        return dp[target]

class Solution:
    def bestTeamScore(self, scores, ages):
        scoresAndAges = [(scores[i], ages[i]) for i in range(len(scores))]
        scoresAndAges.sort(key=lambda x:(x[1],x[0]))
        maxScoreOfYoungerPerson, prevYoungerPersonAge, maxScoreSoFar = -1, -1, -1
        # print(scoresAndAges)
        memo = {}
        def maxScoreRecursiveDP(i, maxScoreOfYoungerPerson, maxScoreSoFar, prevYoungerPersonAge):
            # print(i, maxScoreOfYoungerPerson, maxScoreSoFar, prevYoungerPersonAge)
            if i==len(scores): return 0
            if (i, maxScoreOfYoungerPerson) in memo: return memo[(i, maxScoreOfYoungerPerson)]
            score, age = scoresAndAges[i][0], scoresAndAges[i][1]
            if prevYoungerPersonAge!=age:
                prevYoungerPersonAge = age
                maxScoreOfYoungerPerson = maxScoreSoFar
            maxScoreOfPlayersFromIndexI = 0
            if maxScoreOfYoungerPerson<=score:
                maxScoreOfPlayersFromIndexI = maxScoreRecursiveDP(i+1, maxScoreOfYoungerPerson, max(maxScoreOfYoungerPerson, score, maxScoreSoFar), prevYoungerPersonAge) + score
            maxScoreOfPlayersFromIndexI = max(maxScoreOfPlayersFromIndexI, maxScoreRecursiveDP(i+1, maxScoreOfYoungerPerson, maxScoreSoFar, prevYoungerPersonAge))

            memo[(i, maxScoreOfYoungerPerson)] = maxScoreOfPlayersFromIndexI
            return memo[(i, maxScoreOfYoungerPerson)]
        return maxScoreRecursiveDP(0, maxScoreOfYoungerPerson, prevYoungerPersonAge, maxScoreSoFar)

class Solution:
    def bestTeamScore(self, scores, ages):
        dp = [0 for i in range(max(ages)+1)]
        scoresAndAges = sorted(zip(scores, ages))
        for score,age in scoresAndAges:
            dp[age] = score + max(dp[:age+1])
        return max(dp)

from functools import lru_cache
class Solution:
    def maxProfit(self, prices, fee: int) -> int:
        n = len(prices)

        @lru_cache(maxsize=2*n)
        def memoization(i, canSell):
            if i==n-1: return canSell*(prices[i]-fee)
            if canSell: return max((prices[i]-fee)+memoization(i+1, False), memoization(i+1, True))
            else: return max((-prices[i])+memoization(i+1, True), memoization(i+1, False))

        return memoization(0, False)

class Solution:
    def maxProfit(self, prices, fee: int) -> int:
        n = len(prices)
        dp = [[1e9]*2 for _ in range(n)]
        # can not sell, can sell
        dp[n-1] = [0, prices[n-1]-fee]

        for i in range(n-2, -1, -1):
            dp[i][0] = max((-prices[i])+dp[i+1][1], dp[i+1][0])
            dp[i][1] = max((prices[i]-fee)+dp[i+1][0], dp[i+1][1])
        return dp[0][0]

class Solution:
    def maxProfit(self, prices, fee: int) -> int:
        n = len(prices)
        # can not sell, can sell
        dpIPlusOne = [0, prices[n-1]-fee]

        for i in range(n-2, -1, -1):
            dpI = [0,0]
            dpI[0] = max((-prices[i])+dpIPlusOne[1], dpIPlusOne[0])
            dpI[1] = max((prices[i]-fee)+dpIPlusOne[0], dpIPlusOne[1])
            dpIPlusOne = dpI
        return dpIPlusOne[0]

class Solution:
    def numOfArrays(self, n: int, m: int, k: int) -> int:
        MOD = 10**9+7
        @lru_cache(None)
        def recursion(indexInArr, maxNumInArr, newMaximumsSeenSoFar):
            if newMaximumsSeenSoFar>k: return 0
            if indexInArr==n: return 1 if newMaximumsSeenSoFar==k else 0
            return (maxNumInArr*recursion(indexInArr+1, maxNumInArr, newMaximumsSeenSoFar) + sum(recursion(indexInArr+1, num, newMaximumsSeenSoFar+1) for num in range(maxNumInArr+1, m+1)))%MOD

        return recursion(0, 0, 0)

class Solution:
    def numOfArrays(self, n: int, m: int, k: int) -> int:
        MOD = 10**9+7
        dpIPlusOneMatrix = [[0 for _ in range(k+1)] for _ in range(m+1)]
        for maxNumInArr in range(m+1):
            dpIPlusOneMatrix[maxNumInArr][k] = 1

        for _ in range(n-1, -1, -1):
            dpIMatrix = [[0 for _ in range(k+1)] for _ in range(m+1)]
            for maxNumInArr in range(m+1):
                for newMaximumsSeenSoFar in range(k+1):
                    dpIMatrix[maxNumInArr][newMaximumsSeenSoFar] = maxNumInArr*dpIPlusOneMatrix[maxNumInArr][newMaximumsSeenSoFar]
                    if newMaximumsSeenSoFar!=k:
                        for num in range(maxNumInArr+1, m+1):
                            dpIMatrix[maxNumInArr][newMaximumsSeenSoFar] += dpIPlusOneMatrix[num][newMaximumsSeenSoFar+1] 
                    dpIMatrix[maxNumInArr][newMaximumsSeenSoFar] = (dpIMatrix[maxNumInArr][newMaximumsSeenSoFar])%MOD
            dpIPlusOneMatrix = dpIMatrix
        return dpIPlusOneMatrix[0][0]

