from sortedcontainers import SortedList
from bisect import bisect_left
class Solution:
    def numTeams(self, rating):
        left = SortedList()
        right = SortedList(rating)
        numTrios = 0

        def getSplit(sortedList, num):
            i = bisect_left(sortedList, num)
            return i, len(sortedList) - i

        for num in rating:
            right.remove(num)
            smallerInLeft, largerInLeft = getSplit(left, num)
            smallerInRight, largerInRight = getSplit(right, num)
            numTrios += smallerInLeft*largerInRight + smallerInRight*largerInLeft
            left.add(num)
        return numTrios

class Solution:
    def countSquares(self, matrix):
        m, n = len(matrix), len(matrix[0])

        def isValid(i, j, lastSquareSize):
            if 0<=i<m and 0<=j<n and matrix[i][j]==lastSquareSize:
                return True
            return False

        for squareSize in range(2, min(m, n)+1):
            changed = False
            for i in range(m):
                for j in range(n):
                    if isValid(i,j, squareSize-1) and isValid(i+1, j, squareSize-1) and isValid(i, j+1, squareSize-1) and isValid(i+1, j+1, squareSize-1):
                        matrix[i][j] += 1
                        changed = True
            if not changed: break
        numSquares = 0
        for row in matrix:
            numSquares += sum(row)
        return numSquares


