class Solution:
    def longestZigZag(self, root) -> int:
        maxZigZagPathLength = 0
        @lru_cache(None)
        def dfs(node):
            if not node: return (-1,-1)
            nonlocal maxZigZagPathLength

            _, r1 = dfs(node.left)
            l2, _ = dfs(node.right)

            maxZigZagPathLength = max(maxZigZagPathLength, 1+r1, 1+l2)
            return (1+r1, 1+l2)

        dfs(root)
        return maxZigZagPathLength

# stack based
class Solution:
    def longestZigZag(self, root) -> int:
        maxZigZagPathLength = 0
        # node, pathLenghtSoFar, prevDirectionWasLeft (initial direction doesnt matter as we check both ways anyway, just pass length differently)
        stack = [(root, 0, True)]

        while stack:
            node, pathLenghtSoFar, prevDirectionWasLeft = stack.pop()
            maxZigZagPathLength = max(maxZigZagPathLength, pathLenghtSoFar)        

            if prevDirectionWasLeft:
                if node.right: stack.append((node.right, pathLenghtSoFar+1, False))
                if node.left: stack.append((node.left, 1, True))
            else:
                if node.left: stack.append((node.left, pathLenghtSoFar+1, True))
                if node.right: stack.append((node.right, 1, False))
        return maxZigZagPathLength

class Solution:
    def maxHeight(self, cuboids: List[List[int]]) -> int:
        sortedCuboids = [[0, 0, 0]] + sorted(map(sorted, cuboids))
        dp = [0 for _ in range(len(sortedCuboids))]
        for j in range(1, len(sortedCuboids)):
            for i in range(j):
                if all(sortedCuboids[i][k]<=sortedCuboids[j][k] for k in [0,1,2]):
                    dp[j] = max(dp[j], dp[i]+sortedCuboids[j][2])
        return max(dp)

from collections import Counter
class Solution:
    def maxScoreWords(self, words, letters, score) -> int:
        scoreOfWords = [sum(score[ord(letter)-ord('a')] for letter in word) for word in words]
        wordsCounter, maxScoreSeen = list(map(Counter, words)), 0

        cumulativeSum = deepcopy(scoreOfWords) + [0]
        for i in range(len(scoreOfWords)-2, -1, -1): cumulativeSum[i]+=cumulativeSum[i+1]

        def backtrackingDFS(wordsIndex, remainingLettersCounter, scoreSoFar):
            nonlocal maxScoreSeen
            if scoreSoFar+cumulativeSum[wordsIndex]<=maxScoreSeen: return #pruning

            maxScoreSeen = max(maxScoreSeen, scoreSoFar) # update regardless of reaching the last index
            for index in range(wordsIndex, len(words)):
                if all(neededCountOfLetter<=remainingLettersCounter[letterOfWord] for letterOfWord, neededCountOfLetter in wordsCounter[index].items()):
                    backtrackingDFS(index+1, remainingLettersCounter-wordsCounter[index], scoreSoFar+scoreOfWords[index])

        backtrackingDFS(0, Counter(letters), 0)
        return maxScoreSeen

def minDeleteOperationsForTwoStrings(word1, word2, i, j, dp):
    if i==len(word1):
        return len(word2) - j
    if j==len(word2):
        return len(word1) - i

    if dp[i][j]!=-1:
        return dp[i][j]

    if word1[i]==word2[j]:
        dp[i][j] = minDeleteOperationsForTwoStrings(word1, word2, i+1, j+1)
    else:
        dp[i][j] =  1 + min(minDeleteOperationsForTwoStrings(word1, word2, i+1, j), minDeleteOperationsForTwoStrings(word1, word2, i, j+1))
    return dp[i][j]

