            for startIndex in range(n-delta):
                i, j = startIndex, startIndex+delta
                if s[i]==s[j]:
                    dpCurr.append(dpPrev2[startIndex+1])
                else:
                    dpCurr.append(1+min(dpPrev[startIndex], dpPrev[startIndex+1]))
