class Solution:
    def countPaths(self, grid: List[List[int]]) -> int:

        m, n, MOD = len(grid), len(grid[0]), 10**9+7
        dpArr = [[0 for _ in range(n)] for _ in range(m)]

        def dfs(i, j):
            nonlocal dpArr
            dpArr[i][j] = 1
            for di, dj in [(0,1), (0,-1), (1,0), (-1,0)]:
                newI, newJ = i+di, j+dj
                if 0<=newI<m and 0<=newJ<n and grid[i][j]<grid[newI][newJ]:
                    if dpArr[newI][newJ]==0:
                        dfs(newI, newJ)
                    dpArr[i][j] = (dpArr[i][j]+dpArr[newI][newJ])%MOD

        for i in range(m):
            for j in range(n):
                if dpArr[i][j]==0:
                    dfs(i, j)

        return sum(map(sum, dpArr))%MOD

class Solution:
    def numMusicPlaylists(self, n: int, goal: int, k: int) -> int:

        MOD = 10**9+7
        @lru_cache(None)
        def recursion(n, unusableNumsCount, songsLeftToAdd):
            if songsLeftToAdd==0: return 1
            return ((n-unusableNumsCount)*recursion(n, min(k, unusableNumsCount+1), songsLeftToAdd-1))%MOD

        combinations = [1]
        for r in range(1, n+1):
            combinations.append((combinations[-1]*(n-r+1))//r)

        return sum(combinations[r]*((-1)**r)*recursion(n-r, 0, goal) for r in range(n+1))%MOD

