                    minRowAndColWithAppleDpArr[i][j][1] = min(minRowAndColWithAppleDpArr[i][j][1], minRowAndColWithAppleDpArr[i+1][j][1])

        pizzaCutsDpPrevK = [[0 for _ in range(n)] for _ in range(m)]

