import numpy    
class Solution:
    def numOfWays(self, n):
        # ans is same as [6, 6] * ([3, 2], [2, 2]]**(n-1))
        n, MOD = n-1, 10**9+7
        # adj matrix of directed graph
        M = numpy.matrix([[3, 2], [2, 2]])
        # intital number of paths
        res = [6, 6]
        # matrix exponentiation
        while n:
            if n&1:
                res = res * M % MOD
            M = M * M % MOD
            n //= 2
        return (numpy.sum(res)) % MOD

