def perfectSquaresIterative(n):
    squares = getSquaresTillN(n)
    dp = [1e9 for _ in range(n+1)]
    dp[0] = 0
    for i in range(1, n+1):
        for square in squares:
            if square<=i:
                dp[i] = min(dp[i], dp[i-square]+1)
            else:
                break
    return dp[n]

