def perfectSquaresMath(n):
    squaresSet = set(getSquaresTillN(n))
    if n in squaresSet: 
        return 1
    for i in range(int(math.sqrt(n))+1):
        if n-i*i in squaresSet:
            return 2
    while n%4==0:
        n = n>>2
    if n%8==7:
        return 4
    return 3
