from collections import deque
def perfectSquaresBFS(n):
    squares = getSquaresTillN(n)

    queue = deque()
    queue.append((n,0))
    visited = set([(n,0)])
    while queue:
        elem = queue.popleft()
        num = elem[0]
        jumps = elem[1] 
        for square in squares:
            if square<=num:
                next = (num-square, jumps+1)
                if next[0]==0: return next[1]
                if next not in visited:
                    queue.append(next)
                    visited.add(next)
            else:
                break

