        def recursion(i, j):
            if i==m or j==n: return i==m and (j==n or (all(p[jIndex]=="*" for jIndex in range(j+1, n, 2)) and (n-j)%2==0))
            if j+1<n and p[j+1]=="*":
                if p[j]=="." or s[i]==p[j]:
