class Solution:
    def stoneGameV(self, stoneValue: List[int]) -> int:
        prefixSum = [0]
        for val in stoneValue:
            prefixSum.append(val+prefixSum[-1])

        def getSumInRange(i, j):
            return prefixSum[j+1]-prefixSum[i]

        def getTransitionIndex(i, j):
            low, high = i, j
            while low<high:
                mid = (low+high)//2
                if getSumInRange(i, mid)<getSumInRange(mid+1, j):
                    low = mid + 1
                else:
                    high = mid
            return low

        n = len(stoneValue)
        dpOfScores = [[0 for _ in range(n)] for _ in range(n)]
        dpOfLefts = [[0 for _ in range(n)] for _ in range(n)]
        dpOfRights = [[0 for _ in range(n)] for _ in range(n)]
        for i in range(n):
            dpOfLefts[i][i] = dpOfRights[i][i] = stoneValue[i]

        for delta in range(1, n):
            for startIndex in range(n-delta):
                i, j = startIndex, startIndex+delta
                k = getTransitionIndex(i, j)
                if getSumInRange(i, k)==getSumInRange(k+1,j):
                    dpOfScores[i][j] = max(dpOfLefts[i][k], dpOfRights[k+1][j] if k+1<n else 0)
                else:
                    dpOfScores[i][j] = max(dpOfLefts[i][k-1] if k-1>=0 else 0, dpOfRights[k+1][j] if k+1<n else 0)
                dpOfLefts[i][j] = max(dpOfLefts[i][j-1], getSumInRange(i, j)+dpOfScores[i][j])
                dpOfRights[i][j] = max(dpOfRights[i+1][j], getSumInRange(i, j)+dpOfScores[i][j])

        return dpOfScores[0][-1]



class Solution:
    def stoneGameV(self, stoneValue: List[int]) -> int:
        prefixSum = [0]
        for val in stoneValue:
            prefixSum.append(val+prefixSum[-1])

        def getSumInRange(i, j):
            return prefixSum[j+1]-prefixSum[i]

        n = len(stoneValue)
        dpOfScores = [[0 for _ in range(n)] for _ in range(n)]
        dpOfLefts = [[0 for _ in range(n)] for _ in range(n)]
        dpOfRights = [[0 for _ in range(n)] for _ in range(n)]
        for i in range(n):
            dpOfLefts[i][i] = dpOfRights[i][i] = stoneValue[i]

        for delta in range(1, n):
            k = 0
            for startIndex in range(n-delta):
                i, j = startIndex, startIndex+delta
                while getSumInRange(i, k)<getSumInRange(k+1, j): k += 1
                if getSumInRange(i, k)==getSumInRange(k+1,j):
                    dpOfScores[i][j] = max(dpOfLefts[i][k], dpOfRights[k+1][j] if k+1<n else 0)
                else:
                    dpOfScores[i][j] = max(dpOfLefts[i][k-1] if k-1>=0 else 0, dpOfRights[k+1][j] if k+1<n else 0)
                dpOfLefts[i][j] = max(dpOfLefts[i][j-1], getSumInRange(i, j)+dpOfScores[i][j])
                dpOfRights[i][j] = max(dpOfRights[i+1][j], getSumInRange(i, j)+dpOfScores[i][j])

        return dpOfScores[0][-1]

class Solution:
    def tallestBillboard(self, rods) -> int:
        @lru_cache(None)
        def memoization(i, s1, s2):
            if i==len(rods): return s1 if s1==s2 else 0, 
            return max(memoization(i+1, s1+rods[i], s2), memoization(i+1, s1, s2+rods[i]), memoization(i+1, s1, s2))
        return memoization(0, 0, 0)

class Solution:
    def tallestBillboard(self, rods) -> int:
        @lru_cache(None)
        def memoization(i, diff):
            if i==len(rods): return 0 if diff==0 else -1e9
            return max(rods[i] + memoization(i+1, abs(diff+rods[i])), rods[i]+memoization(i+1, abs(diff-rods[i])), memoization(i+1, diff))
        return max(0, memoization(0, 0)//2)


class Solution:
    def tallestBillboard(self, rods) -> int:
        n, maxSum = len(rods), sum(rods)
        dpIPlusOne = [0]+[-1e9 for _ in range(maxSum)]
        for i in range(n-1, -1, -1):
            dpI = [-1e9 for _ in range(maxSum+1)]
            for diff in range(maxSum-rods[i]+1):
                dpI[diff] = max(rods[i] + dpIPlusOne[abs(diff+rods[i])], rods[i]+dpIPlusOne[abs(diff-rods[i])], dpIPlusOne[diff])
            dpIPlusOne = dpI
        return max(0, dpIPlusOne[0]//2)

class Solution:
    def numTrees(self, n: int) -> int:
        dpArr = [1]*(n+1)
        for i in range(2,n+1):
            dpArr[i] = sum(dpArr[k]*dpArr[i-k-1] for k in range(i))
        return dpArr[n]

